Insert Row.code:
// Insert one row into a table.
// The new row is returned on state.data.
insert(
  // 1) Target table name.
  'users',
  // 2) The record as a plain object (column => value).
  { name: 'Elodie', email: 'elodie@example.org', age: 31 },
  // 3) Optional settings.
  {
    // Print the generated SQL to the run log (handy while developing).
    writeSql: true,
    // Treat these literal strings in the payload as SQL NULL.
    setNull: ["''", "'undefined'"],
  }
);

Insert Multiple Rows.code:
// Insert many rows in one batch.
// Pass an array literal, or a function that derives the array from state.
insertMany(
  'users',
  state => state.data.records,
  { writeSql: true }
);

Update Row.code:
// Update an existing row using a parameterised SQL statement.
// $1, $2... are bound from the `values` array (safe against SQL injection).
sql(
  'UPDATE users SET email = $1, updated_at = NOW() WHERE id = $2;',
  {
    values: [$.data.email, $.data.id],
    writeSql: true,
  }
);

Upsert Row.code:
// Insert-or-update against a unique constraint.
upsert(
  // 1) Target table.
  'users',
  // 2) Conflict target: either a column name with a UNIQUE constraint,
  //    or the literal 'ON CONSTRAINT <constraint_name>'.
  'email',
  // 3) Record to write.
  { name: 'Elodie', email: 'elodie@example.org', age: 31 },
  { writeSql: true }
);

Find Row.code:
// Fetch a single row's value from a relation.
// Result is written to state.data.
findValue({
  // The column to return (or 'id' / uuid column).
  uuid: 'id',
  // The table or view to query.
  relation: 'users',
  // Equality filter (combined with AND).
  where: { email: $.data.email },
  // Optional operator override per column.
  operator: { email: '=' },
});

Find Row via Custom Query.code:
// Run an arbitrary SELECT. Results are on state.data.rows.
sql(
  'SELECT * FROM users WHERE email = $1 LIMIT 1;',
  {
    values: [$.data.email],
    writeSql: true,
  }
);

Find Rows via Custom Query.code:
// Run an arbitrary SELECT returning many rows.
// Available on state.data.rows.
sql(
  'SELECT id, name, email FROM users WHERE created_at > $1 ORDER BY id;',
  {
    values: ['2026-01-01'],
  }
);

Describe Table.code:
// Inspect a table's columns and types.
// Result is written to state.data.
describeTable('users');
